INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (0, "2020/04/30 12:00:00", "リン", 0.0, 24001, 1, 10040, 102601, "2030/12/17 14:59:59", 1, 0.0, 24, "あたしだって\nやるときはやるよ！", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (1, "2020/04/30 12:00:00", "リン", 0.0, 24002, 1, 10040, 102601, "2030/12/17 14:59:59", 1, 0.0, 24, "ふぅ…\nこれであたしの仕事は\n終わりだね", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (2, "2020/04/30 12:00:00", "リン", 0.0, 24003, 1, 10040, 102601, "2030/12/17 14:59:59", 1, 0.0, 24, "終わった終わった\n一人でもなんとか\nなるもんだね", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (3, "2020/04/30 12:00:00", "リン", 0.0, 24004, 2, 10040, 102601, "2030/12/17 14:59:59", 2, 0.0, 24, "やったね！\nこれでようやく\nサボれるよ…", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (4, "2020/04/30 12:00:00", "リン", 0.0, 24005, 1, 10040, 102601, "2030/12/17 14:59:59", 1, 0.0, 24, "チーズが欲しいなら\nきちんと働いて\n買いに来なよ", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (5, "2020/04/30 12:00:00", "リン", 0.0, 24006, 2, 10040, 102601, "2030/12/17 14:59:59", 2, 0.0, 24, "あたしを敵に回した\n恐ろしさ\n思い知ったか！", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (6, "2020/04/30 12:00:00", "リン", 0.0, 24007, 2, 10040, 102601, "2030/12/17 14:59:59", 2, 0.0, 24, "あたしも意外と\nやるもんでしょ？", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (7, "2020/04/30 12:00:00", "リン", 0.0, 24008, 4, 10040, 102601, "2030/12/17 14:59:59", 4, 0.0, 24, "疲れた…\nねずみの逃げ足\n速すぎるよ…", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (8, "2020/04/30 12:00:00", "リン", 0.0, 24009, 4, 10040, 102601, "2030/12/17 14:59:59", 4, 0.0, 24, "このままじゃ\nまっひ～に\n叱られちゃうよ", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (9, "2020/04/30 12:00:00", "リン", 0.0, 24010, 4, 10040, 102601, "2030/12/17 14:59:59", 4, 0.0, 24, "まじめに\nやったんだけどな…\n悔しいな～", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10, "2020/04/30 12:00:00", "リン", 0.0, 24011, 4, 10040, 102601, "2030/12/17 14:59:59", 4, 0.0, 24, "やられた…\nねずみって意外と\nてごわいね", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (11, "2020/04/30 12:00:00", "リン", 0.0, 24012, 4, 10040, 102601, "2030/12/17 14:59:59", 4, 0.0, 24, "おのれ～\nあたしのチーズを\n盗みやがって～！", 0.0);
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (12, "2020/04/30 12:00:00", "リン", 0.0, 24013, 4, 10040, 102601, "2030/12/17 14:59:59", 1, 1.81, 24, "疲れた…\nけど、次こそは\n守り抜くよ…", 0.0);
